mapper.select:
SELECT * FROM transaction
WHERE user_id = #{userId}

    AND date >= #{startDate}


    AND date <= #{endDate}

ORDER BY date DESC, created_at DESC

SELECT * FROM transaction
WHERE user_id = #{userId} AND type = #{type}

    AND date >= #{startDate}


    AND date <= #{endDate}

ORDER BY date DESC, created_at DESC

SELECT * FROM transaction
WHERE user_id = #{userId} AND category_id = #{categoryId}

    AND date >= #{startDate}


    AND date <= #{endDate}

ORDER BY date DESC, created_at DESC

SELECT COALESCE(SUM(amount), 0) FROM transaction
WHERE user_id = #{userId} AND type = 'income'

    AND date >= #{startDate}


    AND date <= #{endDate}

SELECT COALESCE(SUM(amount), 0) FROM transaction
WHERE user_id = #{userId} AND type = 'expense'

    AND date >= #{startDate}


    AND date <= #{endDate}

SELECT COUNT(*) FROM transaction
WHERE user_id = #{userId}

    AND date >= #{startDate}


    AND date <= #{endDate}

SELECT t.category_id AS categoryId, t.category_name AS categoryName, c.icon AS categoryIcon, c.color AS categoryColor, t.type AS type, SUM(t.amount) AS amount, COUNT(*) AS count FROM transaction t LEFT JOIN category c ON t.category_id = c.id WHERE t.user_id = #{userId}
AND t.date >= #{startDate}
AND t.date <= #{endDate}
GROUP BY t.category_id, t.type ORDER BY amount DESC

SELECT t.date AS date, COALESCE(SUM(CASE WHEN t.type = 'income' THEN t.amount ELSE 0 END), 0) AS income, COALESCE(SUM(CASE WHEN t.type = 'expense' THEN t.amount ELSE 0 END), 0) AS expense, COALESCE(SUM(CASE WHEN t.type = 'income' THEN t.amount ELSE 0 END), 0) - COALESCE(SUM(CASE WHEN t.type = 'expense' THEN t.amount ELSE 0 END), 0) AS balance FROM transaction t WHERE t.user_id = #{userId}
AND t.date >= #{startDate}
AND t.date <= #{endDate}
GROUP BY t.date ORDER BY t.date DESC LIMIT 30
